 20→//#region src/backends/protocol.ts
 21→/**
 22→* Type guard to check if a backend supports execution.
 23→*
 24→* @param backend - Backend instance to check
 25→* @returns True if the backend implements SandboxBackendProtocol
 26→*/
 27→function isSandboxBackend(backend) {
 28→	return typeof backend.execute === "function" && typeof backend.id === "string";
 29→}
 30→const SANDBOX_ERROR_SYMBOL = Symbol.for("sandbox.error");
 31→/**
 32→* Custom error class for sandbox operations.
 33→*
 34→* @param message - Human-readable error description
 35→* @param code - Structured error code for programmatic handling
 36→* @returns SandboxError with message and code
 37→*
 38→* @example
 39→* ```typescript
 40→* try {
 41→*   await sandbox.execute("some command");
 42→* } catch (error) {
 43→*   if (error instanceof SandboxError) {
 44→*     switch (error.code) {
 45→*       case "NOT_INITIALIZED":
 46→*         await sandbox.initialize();
 47→*         break;
 48→*       case "COMMAND_TIMEOUT":
 49→*         console.error("Command took too long");
 50→*         break;
 51→*       default:
 52→*         throw error;
 53→*     }
 54→*   }
 55→* }
 56→* ```
 57→*/
 58→var SandboxError = class SandboxError extends Error {
 59→	/** Symbol for identifying sandbox error instances */
 60→	[SANDBOX_ERROR_SYMBOL] = true;
 61→	/** Error name for instanceof checks and logging */
 62→	name = "SandboxError";
 63→	/**
 64→	* Creates a new SandboxError.
 65→	*
 66→	* @param message - Human-readable error description
 67→	* @param code - Structured error code for programmatic handling
 68→	*/
 69→	constructor(message, code, cause) {
 70→		super(message);
 71→		this.code = code;
 72→		this.cause = cause;
 73→		Object.setPrototypeOf(this, SandboxError.prototype);
 74→	}
 75→	static isInstance(error) {
 76→		return typeof error === "object" && error !== null && error[SANDBOX_ERROR_SYMBOL] === true;
 77→	}
 78→};
