 81→//#region src/backends/utils.ts
 82→/**
 83→* Shared utility functions for memory backend implementations.
 84→*
 85→* This module contains both user-facing string formatters and structured
 86→* helpers used by backends and the composite router. Structured helpers
 87→* enable composition without fragile string parsing.
 88→*/
 89→const EMPTY_CONTENT_WARNING = "System reminder: File exists but has empty contents";
 90→const MAX_LINE_LENGTH = 1e4;
 91→const LINE_NUMBER_WIDTH = 6;
 92→const TOOL_RESULT_TOKEN_LIMIT = 2e4;
 93→const TRUNCATION_GUIDANCE = "... [results truncated, try being more specific with your parameters]";
 94→/**
 95→* Sanitize tool_call_id to prevent path traversal and separator issues.
 96→*
 97→* Replaces dangerous characters (., /, \) with underscores.
 98→*/
 99→function sanitizeToolCallId(toolCallId) {
100→	return toolCallId.replace(/\./g, "_").replace(/\//g, "_").replace(/\\/g, "_");
101→}
102→/**
103→* Format file content with line numbers (cat -n style).
104→*
105→* Chunks lines longer than MAX_LINE_LENGTH with continuation markers (e.g., 5.1, 5.2).
106→*
107→* @param content - File content as string or list of lines
108→* @param startLine - Starting line number (default: 1)
109→* @returns Formatted content with line numbers and continuation markers
110→*/
111→function formatContentWithLineNumbers(content, startLine = 1) {
112→	let lines;
113→	if (typeof content === "string") {
114→		lines = content.split("\n");
115→		if (lines.length > 0 && lines[lines.length - 1] === "") lines = lines.slice(0, -1);
116→	} else lines = content;
117→	const resultLines = [];
118→	for (let i = 0; i < lines.length; i++) {
119→		const line = lines[i];
120→		const lineNum = i + startLine;
121→		if (line.length <= MAX_LINE_LENGTH) resultLines.push(`${lineNum.toString().padStart(LINE_NUMBER_WIDTH)}\t${line}`);
122→		else {
123→			const numChunks = Math.ceil(line.length / MAX_LINE_LENGTH);
124→			for (let chunkIdx = 0; chunkIdx < numChunks; chunkIdx++) {
125→				const start = chunkIdx * MAX_LINE_LENGTH;
126→				const end = Math.min(start + MAX_LINE_LENGTH, line.length);
127→				const chunk = line.substring(start, end);
128→				if (chunkIdx === 0) resultLines.push(`${lineNum.toString().padStart(LINE_NUMBER_WIDTH)}\t${chunk}`);
129→				else {
130→					const continuationMarker = `${lineNum}.${chunkIdx}`;
131→					resultLines.push(`${continuationMarker.padStart(LINE_NUMBER_WIDTH)}\t${chunk}`);
132→				}
133→			}
134→		}
135→	}
136→	return resultLines.join("\n");
137→}
138→/**
139→* Check if content is empty and return warning message.
140→*
141→* @param content - Content to check
142→* @returns Warning message if empty, null otherwise
143→*/
144→function checkEmptyContent(content) {
145→	if (!content || content.trim() === "") return EMPTY_CONTENT_WARNING;
146→	return null;
147→}
148→/**
149→* Convert FileData to plain string content.
150→*
151→* @param fileData - FileData object with 'content' key
152→* @returns Content as string with lines joined by newlines
153→*/
154→function fileDataToString(fileData) {
155→	return fileData.content.join("\n");
156→}
157→/**
158→* Create a FileData object with timestamps.
159→*
160→* @param content - File content as string
161→* @param createdAt - Optional creation timestamp (ISO format)
162→* @returns FileData object with content and timestamps
163→*/
164→function createFileData(content, createdAt) {
165→	const lines = typeof content === "string" ? content.split("\n") : content;
166→	const now = (/* @__PURE__ */ new Date()).toISOString();
167→	return {
168→		content: lines,
169→		created_at: createdAt || now,
170→		modified_at: now
171→	};
172→}
173→/**
174→* Update FileData with new content, preserving creation timestamp.
175→*
176→* @param fileData - Existing FileData object
177→* @param content - New content as string
178→* @returns Updated FileData object
179→*/
180→function updateFileData(fileData, content) {
181→	const lines = typeof content === "string" ? content.split("\n") : content;
182→	const now = (/* @__PURE__ */ new Date()).toISOString();
183→	return {
184→		content: lines,
185→		created_at: fileData.created_at,
186→		modified_at: now
187→	};
188→}
189→/**
190→* Format file data for read response with line numbers.
191→*
192→* @param fileData - FileData object
193→* @param offset - Line offset (0-indexed)
194→* @param limit - Maximum number of lines
195→* @returns Formatted content or error message
196→*/
197→function formatReadResponse(fileData, offset, limit) {
198→	const content = fileDataToString(fileData);
199→	const emptyMsg = checkEmptyContent(content);
200→	if (emptyMsg) return emptyMsg;
201→	const lines = content.split("\n");
202→	const startIdx = offset;
203→	const endIdx = Math.min(startIdx + limit, lines.length);
204→	if (startIdx >= lines.length) return `Error: Line offset ${offset} exceeds file length (${lines.length} lines)`;
205→	return formatContentWithLineNumbers(lines.slice(startIdx, endIdx), startIdx + 1);
206→}
207→/**
208→* Perform string replacement with occurrence validation.
209→*
210→* @param content - Original content
211→* @param oldString - String to replace
212→* @param newString - Replacement string
213→* @param replaceAll - Whether to replace all occurrences
214→* @returns Tuple of [new_content, occurrences] on success, or error message string
215→*
216→* Special case: When both content and oldString are empty, this sets the initial
217→* content to newString. This allows editing empty files by treating empty oldString
218→* as "set initial content" rather than "replace nothing".
219→*/
220→function performStringReplacement(content, oldString, newString, replaceAll) {
221→	if (content === "" && oldString === "") return [newString, 0];
222→	if (oldString === "") return "Error: oldString cannot be empty when file has content";
223→	const occurrences = content.split(oldString).length - 1;
224→	if (occurrences === 0) return `Error: String not found in file: '${oldString}'`;
225→	if (occurrences > 1 && !replaceAll) return `Error: String '${oldString}' has multiple occurrences (appears ${occurrences} times) in file. Use replace_all=True to replace all instances, or provide a more specific string with surrounding context.`;
226→	return [content.split(oldString).join(newString), occurrences];
227→}
228→/**
229→* Truncate list or string result if it exceeds token limit (rough estimate: 4 chars/token).
230→*/
231→function truncateIfTooLong(result) {
232→	if (Array.isArray(result)) {
233→		const totalChars = result.reduce((sum, item) => sum + item.length, 0);
234→		if (totalChars > TOOL_RESULT_TOKEN_LIMIT * 4) {
235→			const truncateAt = Math.floor(result.length * TOOL_RESULT_TOKEN_LIMIT * 4 / totalChars);
236→			return [...result.slice(0, truncateAt), TRUNCATION_GUIDANCE];
237→		}
238→		return result;
239→	}
240→	if (result.length > TOOL_RESULT_TOKEN_LIMIT * 4) return result.substring(0, TOOL_RESULT_TOKEN_LIMIT * 4) + "\n... [results truncated, try being more specific with your parameters]";
241→	return result;
242→}
243→/**
244→* Validate and normalize a directory path.
245→*
246→* Ensures paths are safe to use by preventing directory traversal attacks
247→* and enforcing consistent formatting. All paths are normalized to use
248→* forward slashes and start with a leading slash.
249→*
250→* This function is designed for virtual filesystem paths and rejects
251→* Windows absolute paths (e.g., C:/..., F:/...) to maintain consistency
252→* and prevent path format ambiguity.
253→*
254→* @param path - Path to validate
255→* @returns Normalized path starting with / and ending with /
256→* @throws Error if path is invalid
257→*
258→* @example
259→* ```typescript
260→* validatePath("foo/bar")  // Returns: "/foo/bar/"
261→* validatePath("/./foo//bar")  // Returns: "/foo/bar/"
262→* validatePath("../etc/passwd")  // Throws: Path traversal not allowed
263→* validatePath("C:\\Users\\file")  // Throws: Windows absolute paths not supported
264→* ```
265→*/
266→function validatePath(path) {
267→	const pathStr = path || "/";
268→	if (!pathStr || pathStr.trim() === "") throw new Error("Path cannot be empty");
269→	let normalized = pathStr.startsWith("/") ? pathStr : "/" + pathStr;
270→	if (!normalized.endsWith("/")) normalized += "/";
271→	return normalized;
272→}
273→/**
274→* Search files dict for paths matching glob pattern.
275→*
276→* @param files - Dictionary of file paths to FileData
277→* @param pattern - Glob pattern (e.g., `*.py`, `**\/*.ts`)
278→* @param path - Base path to search from
279→* @returns Newline-separated file paths, sorted by modification time (most recent first).
280→*          Returns "No files found" if no matches.
281→*
282→* @example
283→* ```typescript
284→* const files = {"/src/main.py": FileData(...), "/test.py": FileData(...)};
285→* globSearchFiles(files, "*.py", "/");
286→* // Returns: "/test.py\n/src/main.py" (sorted by modified_at)
287→* ```
288→*/
289→function globSearchFiles(files, pattern, path = "/") {
290→	let normalizedPath;
291→	try {
292→		normalizedPath = validatePath(path);
293→	} catch {
294→		return "No files found";
295→	}
296→	const filtered = Object.fromEntries(Object.entries(files).filter(([fp]) => fp.startsWith(normalizedPath)));
