 59→function createContentPreview(content: string, headLines = 5, tailLines = 5): string {
 60→  const lines = content.split('\n');
 61→  if (lines.length <= headLines + tailLines) {
 62→    return lines.map((line, i) => `${i + 1}\t${line.substring(0, 1000)}`).join('\n');
 63→  }
 64→  const head = lines.slice(0, headLines).map((line, i) => `${i + 1}\t${line.substring(0, 1000)}`).join('\n');
 65→  const truncation = `\n... [${lines.length - headLines - tailLines} lines truncated] ...\n`;
 66→  const tailStart = lines.length - tailLines + 1;
 67→  const tail = lines.slice(-tailLines).map((line, i) => `${tailStart + i}\t${line.substring(0, 1000)}`).join('\n');
 68→  return head + truncation + tail;
 69→}
