 71→const TOO_LARGE_MSG = `Tool result too large, the result of this tool call {tool_call_id} was saved in the filesystem at this path: {file_path}
 72→You can read the result from the filesystem by using the read_file tool, but make sure to only read part of the result at a time.
 73→You can do this by specifying an offset and limit in the read_file tool call.
 74→For example, to read the first 100 lines, you can use the read_file tool with offset=0 and limit=100.
 75→
 76→Here is a preview showing the head and tail of the result (lines of the form
 77→... [N lines truncated] ...
 78→indicate omitted lines in the middle of the content):
 79→
 80→{content_sample}`;
 81→
 82→/**
 83→ * Creates a middleware that evicts large tool results to the VFS filesystem
 84→ * with a stricter threshold than the default deepagents SDK.
 85→ *
 86→ * Custom middleware runs innermost in the chain, so our eviction happens
 87→ * before the SDK's built-in filesystem middleware sees the result.
 88→ */
 89→function createStrictToolEvictionMiddleware(backend: SandboxBackendProtocol) {
 90→  return createMiddleware({
 91→    name: 'StrictToolEvictionMiddleware',
 92→    wrapToolCall: async (request, handler) => {
 93→      const toolName = request.toolCall?.name;
 94→      if (toolName && TOOLS_EXCLUDED_FROM_EVICTION.includes(toolName)) {
 95→        return handler(request);
 96→      }
 97→
 98→      const result = await handler(request);
 99→
100→      if (ToolMessage.isInstance(result) && typeof result.content === 'string' && result.content.length > STRICT_CHAR_LIMIT) {
101→        const toolCallId = request.toolCall?.id || result.tool_call_id;
102→        const evictPath = `/large_tool_results/${sanitizeToolCallId(toolCallId)}`;
103→
104→        let contentToWrite = result.content;
105→        try {
106→          const parsed = JSON.parse(contentToWrite);
107→          contentToWrite = JSON.stringify(parsed, null, 2);
108→        } catch {}
109→
110→        const writeResult = await backend.write(evictPath, contentToWrite);
111→        if (writeResult.error) return result;
112→
113→        const contentSample = createContentPreview(result.content);
114→        return new ToolMessage({
115→          content: TOO_LARGE_MSG
116→            .replace('{tool_call_id}', result.tool_call_id)
117→            .replace('{file_path}', evictPath)
118→            .replace('{content_sample}', contentSample),
119→          tool_call_id: result.tool_call_id,
120→          name: result.name,
121→          id: result.id,
122→          artifact: (result as any).artifact,
123→          status: result.status,
124→          metadata: result.metadata,
125→          additional_kwargs: result.additional_kwargs,
126→          response_metadata: result.response_metadata,
127→        });
128→      }
129→
130→      return result;
131→    },
132→  });
133→}
