import { ToolMessage } from '@langchain/core/messages';
import { createMiddleware } from 'langchain';
import { formatError } from '../../common/utils';

function formatToolFailureContent(error) {
  return `Tool error: Please check your input and try again. (${error})`;
}

export function createToolErrorMiddleware(): ReturnType<typeof createMiddleware> {
  return createMiddleware({
    name: 'ToolErrorMiddleware',
    wrapToolCall: async (request, handler) => {
      try {
        return await handler(request);
      } catch (error) {
        const content = formatToolFailureContent(error);

        // Return a ToolMessage so LangChain can continue the agent loop
        // instead of aborting the whole run on tool exceptions.
        return new ToolMessage({
          content,
          name: request.toolCall.name,
          tool_call_id: request.toolCall.id ?? '',
          status: 'error',
          artifact: { error: formatError(error) },
        });
      }
    },
  });
}

