  1→import { AIMessageChunk, isAIMessageChunk } from '@langchain/core/messages';
  2→import { randomUUID } from 'crypto';
  3→import { appendFile } from 'fs/promises';
  4→import path from 'path';
  5→import {
  6→  ALLOW_TOOL_INPUT,
  7→  ENodeName,
  8→  EToolName,
  9→  SUMMARIZED_TOOL_CALL_RESULT_NAMES,
 10→  TalkableAgents,
 11→} from '../../common/constant';
 12→import { IAskUserPayload } from '../../common/ask-user';
 13→import { log } from '../../logger';
 14→import { IGraphEvent } from '../agents.service';
 15→import {
 16→  extractTokenUsage,
 17→  extractToolError,
 18→  getToolArgs,
 19→  parseChunk,
 20→  resolveToolOutput,
 21→  tryJSONStringify,
 22→} from './utils';
 23→
 24→const STREAM_DEBUG = process.env.STREAM_DEBUG === 'true';
 25→const STREAM_DEBUG_INCLUDE_DATA = process.env.STREAM_DEBUG_INCLUDE_DATA === 'true';
 26→const TASK_TOOL_NAME = 'task';
 27→
 28→type StreamMetadata = Record<string, unknown>;
 29→type StreamSubagentInfo = { type: string; namespace: string };
 30→type StreamContext = {
 31→  run_id: string;
 32→  name: string;
 33→  data: Record<string, unknown>;
 34→  node: ENodeName | undefined;
 35→  metadata?: StreamMetadata;
 36→};
 37→
 38→export interface ToolInputState {
 39→  inputtingTool: string | undefined;
 40→  subagentNamespaces?: Record<string, string>;
 41→}
 42→
 43→function makeEvent<T>(
 44→  event: string,
 45→  node: ENodeName | undefined,
 46→  data?: T,
 47→  subagent?: StreamSubagentInfo,
 48→): IGraphEvent<T> {
 49→  return {
 50→    id: randomUUID(),
 51→    timestamp: performance.now(),
 52→    event,
 53→    node,
 54→    data,
 55→    ...(subagent ? { subagent_type: subagent.type, subagent_namespace: subagent.namespace } : {}),
 56→  };
 57→}
 58→
 59→function asString(value: unknown): string | undefined {
 60→  return typeof value === 'string' ? value : undefined;
 61→}
 62→
 63→function getRegisteredSubagentNamespaces(state: ToolInputState): Record<string, string> {
 64→  if (!state.subagentNamespaces) {
 65→    state.subagentNamespaces = {};
 66→  }
 67→  return state.subagentNamespaces;
 68→}
 69→
 70→function expandNamespaceToken(token: string): string[] {
 71→  const trimmed = token.trim();
 72→  if (!trimmed) {
 73→    return [];
 74→  }
 75→  if (!trimmed.includes(':')) {
 76→    return [trimmed];
 77→  }
 78→  const segmented = trimmed.match(/[a-zA-Z_]+:[^:|,]+/g);
 79→  return segmented?.length ? segmented.map(segment => segment.trim()).filter(Boolean) : [trimmed];
 80→}
 81→
 82→function extractNamespace(metadata?: StreamMetadata): string[] {
 83→  if (!metadata) {
 84→    return [];
 85→  }
 86→
 87→  const rawCandidates: unknown[] = [
 88→    metadata.namespace,
 89→    metadata.langgraph_path,
 90→    metadata.checkpoint_ns,
 91→  ];
 92→
 93→  const flattened = rawCandidates.flatMap(candidate => {
 94→    if (Array.isArray(candidate)) {
 95→      return candidate;
 96→    }
 97→    if (typeof candidate === 'string') {
 98→      return candidate.split(/[|,]/g);
 99→    }
100→    return [];
101→  });
102→
103→  const namespace = flattened
104→    .flatMap(value => (typeof value === 'string' ? expandNamespaceToken(value) : []))
105→    .map(segment => segment.trim())
106→    .filter(segment => segment && segment !== 'root');
107→
108→  return Array.from(new Set(namespace));
109→}
110→
111→export function getStreamSource(
112→  metadata?: StreamMetadata,
113→  fallbackNode?: ENodeName,
114→): { kind: 'main' | 'subagent'; key: string; label?: string; namespace?: string[] } {
115→  const namespace = extractNamespace(metadata);
116→  const subagentKey = namespace.find(segment => segment.startsWith('tools:'));
117→  const label = asString(metadata?.lc_agent_name) ?? fallbackNode;
118→
119→  if (subagentKey) {
120→    return {
121→      kind: 'subagent',
122→      key: subagentKey,
123→      label,
124→      namespace,
125→    };
126→  }
127→
128→  return {
129→    kind: 'main',
130→    key: 'main',
131→    label,
132→    namespace,
133→  };
134→}
135→
136→function getToolsNamespace(metadata?: StreamMetadata): string | undefined {
137→  return extractNamespace(metadata).find(segment => segment.startsWith('tools:'));
138→}
139→
140→function parseTaskSubagentType(input: string | undefined): string | undefined {
141→  if (!input) {
142→    return undefined;
143→  }
144→  try {
145→    const parsed = JSON.parse(input) as Record<string, unknown>;
146→    return typeof parsed.subagent_type === 'string' ? parsed.subagent_type : undefined;
147→  } catch {
148→    return undefined;
149→  }
150→}
151→
152→function registerTaskSubagentNamespace(
153→  toolName: string,
154→  data: Record<string, unknown>,
155→  metadata: StreamMetadata | undefined,
156→  state: ToolInputState,
157→): void {
158→  if (toolName !== TASK_TOOL_NAME) {
159→    return;
160→  }
161→
162→  const toolsNamespace = getToolsNamespace(metadata);
163→  const rawInput = ((data.input as { input?: string } | undefined)?.input) || undefined;
164→  const subagentType = parseTaskSubagentType(rawInput);
165→  if (!toolsNamespace || !subagentType) {
166→    return;
167→  }
168→  getRegisteredSubagentNamespaces(state)[toolsNamespace] = subagentType;
169→}
170→
171→function resolveSubagentInfo(
172→  metadata: StreamMetadata | undefined,
173→  state: ToolInputState,
174→): StreamSubagentInfo | undefined {
175→  const namespaceSegments = extractNamespace(metadata);
176→  for (const [registeredNamespace, subagentType] of Object.entries(getRegisteredSubagentNamespaces(state))) {
177→    const matchesRegisteredNamespace = namespaceSegments.some(
178→      segment => segment === registeredNamespace || segment.startsWith(`${registeredNamespace}:`),
179→    );
180→    if (matchesRegisteredNamespace) {
181→      return {
182→        type: subagentType,
183→        namespace: registeredNamespace,
184→      };
185→    }
186→  }
187→
188→  return undefined;
189→}
190→
191→function shouldEmitToolInputPreview(toolName: string | undefined): boolean {
192→  return !!toolName && ALLOW_TOOL_INPUT.includes(toolName as EToolName);
193→}
194→
195→function shouldSummarizeToolCallResult(toolName: string): boolean {
196→  return SUMMARIZED_TOOL_CALL_RESULT_NAMES.includes(toolName);
197→}
198→
199→function summarizeToolCallResult(text: string): string {
200→  if (text.length <= 100) {
201→    return text;
202→  }
203→
204→  return `${text.slice(0, 50)}\n...\n${text.slice(-50)}`;
205→}
206→
207→function createToolInputEvent(
208→  toolName: string,
209→  toolCallChunks: AIMessageChunk['tool_call_chunks'],
210→  node: ENodeName | undefined,
211→  subagent?: StreamSubagentInfo,
212→): IGraphEvent | undefined {
213→  if (!shouldEmitToolInputPreview(toolName)) {
214→    return undefined;
215→  }
216→
217→  return makeEvent(
218→    'tool-input',
219→    node,
220→    { name: toolName, input: getToolArgs(toolCallChunks) },
221→    subagent,
222→  );
223→}
224→
225→function writeStreamDebugLog(event: string, name: string, node: ENodeName | undefined, data: Record<string, unknown>): void {
226→  if (!STREAM_DEBUG) {
227→    return;
228→  }
229→
230→  const debugData = STREAM_DEBUG_INCLUDE_DATA
231→    ? data
232→    : {
233→      keys: Object.keys(data || {}).slice(0, 12),
234→      size: JSON.stringify(data || {}).length,
235→    };
236→  const debugInfo = JSON.stringify({ event, name, node, data: debugData });
237→  const debugPath = path.join(process.cwd(), 'DEBUG.txt');
238→  void appendFile(debugPath, debugInfo + '\n', 'utf-8');
239→}
240→
241→export function handleChainStart(
242→  name: string,
243→  node: ENodeName | undefined,
244→  subagent?: StreamSubagentInfo,
245→): IGraphEvent | undefined {
246→  if (!node || !(TalkableAgents as string[]).includes(name)) return undefined;
247→  log('agent-start: ' + name);
248→  return makeEvent('agent-start', node, name, subagent);
249→}
250→
251→export function handleChainEnd(
252→  name: string,
253→  node: ENodeName | undefined,
254→  subagent?: StreamSubagentInfo,
255→): IGraphEvent | undefined {
256→  if (!node || !(TalkableAgents as string[]).includes(name)) return undefined;
257→  log('agent-end: ' + name);
258→  return makeEvent('agent-end', node, name, subagent);
259→}
260→
261→export function handleChatModelStart(node: ENodeName | undefined, subagent?: StreamSubagentInfo): IGraphEvent | undefined {
262→  log('chat-start: ' + node);
263→  return makeEvent('assistant-start', node, node, subagent);
264→}
265→
266→export function handleChatModelEnd(
267→  node: ENodeName | undefined,
268→  data?: Record<string, unknown>,
269→  subagent?: StreamSubagentInfo,
270→): IGraphEvent | undefined {
271→  log('chat-end: ' + node);
272→  const usage = extractTokenUsage(data);
273→  return makeEvent('assistant-end', node, {
274→    node,
275→    ...(usage ? { usage } : {}),
276→  }, subagent);
277→}
278→
279→export function handleChatModelStream(
280→  data: { chunk: unknown },
281→  node: ENodeName | undefined,
282→  state: ToolInputState,
283→  subagent?: StreamSubagentInfo,
284→): IGraphEvent | undefined {
285→  // eslint-disable-next-line @typescript-eslint/no-explicit-any
286→  if (!data.chunk || !isAIMessageChunk(data.chunk as any)) return undefined;
287→
288→  const chunk = data.chunk as AIMessageChunk;
289→  const { tool_call_chunks } = chunk;
290→  const { text, thinking, tool } = parseChunk(chunk);
291→
292→  if (tool) {
293→    state.inputtingTool = tool;
294→    return createToolInputEvent(tool, tool_call_chunks, node, subagent);
295→  }
296→
297→  if (state.inputtingTool && tool_call_chunks?.length) {
298→    return createToolInputEvent(state.inputtingTool, tool_call_chunks, node, subagent);
299→  }
300→
301→  if (text || thinking) {
302→    return makeEvent('assistant', node, { thinking, content: text }, subagent);
303→  }
304→
305→  return undefined;
306→}
307→
308→export function handleChainStream(
309→  data: { chunk?: Record<string, unknown> },
310→  node: ENodeName | undefined,
311→  subagent?: StreamSubagentInfo,
312→): IGraphEvent | undefined {
313→  const interrupts = data.chunk?.__interrupt__;
314→  if (!Array.isArray(interrupts) || interrupts.length === 0) {
315→    return undefined;
316→  }
317→
318→  const interrupt = interrupts[0] as { id?: string; value?: unknown };
319→  if (!interrupt?.value || typeof interrupt.value !== 'object') {
320→    return undefined;
321→  }
322→
323→  const payload = interrupt.value as IAskUserPayload;
324→  const payloadNode = payload.agent && TalkableAgents.includes(payload.agent) ? payload.agent : node;
325→  log(`ask-user interrupt: ${JSON.stringify(payload)}`);
326→  return makeEvent('interrupt', payloadNode, { interruptId: interrupt.id, ...payload }, subagent);
327→}
328→
329→export function handleToolStart(
330→  runId: string,
331→  name: string,
332→  data: { input: { input: string } },
333→  node: ENodeName | undefined,
334→  state: ToolInputState,
335→  subagent?: StreamSubagentInfo,
336→): IGraphEvent | undefined {
337→  state.inputtingTool = undefined;
338→  log(`tool-start: ${name}`);
339→
340→  // ask-user 工具发出专属事件，前端将其强制展示（不折叠）
341→  if (name === EToolName.AskUser) {
342→    return undefined;
343→  }
344→
345→  const input: string = data.input.input;
346→  log(`tool-call(${name}): ${input}`);
347→
348→  return makeEvent('tool-call', node, { id: runId, name, input }, subagent);
349→}
350→
351→export function handleToolEnd(
352→  runId: string,
353→  name: string,
354→  data: { output: { artifact: unknown; content: unknown } },
355→  node: ENodeName | undefined,
356→  subagent?: StreamSubagentInfo,
357→): IGraphEvent | undefined {
358→  if (name === EToolName.AskUser) {
359→    return undefined;
360→  }
361→
362→  const { artifact, content } = data.output;
363→
364→  if (artifact instanceof Error) {
365→    log(`tool-call-result(${name}).error: ${artifact.message}`);
366→  } else {
367→    log(`tool-call-result(${name}).artifact: ${tryJSONStringify(artifact) ?? 'undefined'}`);
368→  }
369→  log(`tool-call-result(${name}).content: ${content}`);
370→
371→  const output = resolveToolOutput(artifact, content);
372→  const toolError = extractToolError(artifact) ?? extractToolError(output);
373→  const outputStr = artifact instanceof Error
374→    ? (artifact as Error).message
375→    : toolError ?? (typeof output === 'string' ? output : tryJSONStringify(output) ?? '');
376→  const outputLength = outputStr.length;
377→  const summarizedOutput = shouldSummarizeToolCallResult(name)
378→    ? summarizeToolCallResult(outputStr)
379→    : outputStr;
380→
381→  return makeEvent('tool-call-result', node, {
382→    id: runId,
383→    name,
384→    outputLength,
385→    ...(artifact instanceof Error || toolError
386→      ? { error: summarizedOutput }
387→      : { output: shouldSummarizeToolCallResult(name) ? summarizedOutput : output }),
388→  }, subagent);
389→}
390→
391→export function handleToolError(
392→  runId: string,
393→  name: string,
394→  data: { error?: unknown },
395→  node: ENodeName | undefined,
396→  subagent?: StreamSubagentInfo,
397→): IGraphEvent | undefined {
398→  if (name === EToolName.AskUser) {
399→    return undefined;
400→  }
401→
402→  const message = extractToolError(data.error) ?? tryJSONStringify(data.error) ?? 'Tool execution failed';
403→  log(`tool-call-result(${name}).error: ${message}`);
404→  const summarizedMessage = shouldSummarizeToolCallResult(name)
405→    ? summarizeToolCallResult(message)
406→    : message;
407→
408→  return makeEvent('tool-call-result', node, {
409→    id: runId,
410→    name,
411→    outputLength: message.length,
412→    error: summarizedMessage,
413→  }, subagent);
414→}
415→
416→function buildSubagentInfo(name: string, data: Record<string, unknown>, metadata: StreamMetadata | undefined, state: ToolInputState) {
417→  if (name === TASK_TOOL_NAME) {
418→    registerTaskSubagentNamespace(name, data, metadata, state);
419→  }
420→
421→  return resolveSubagentInfo(metadata, state);
422→}
423→
424→export function dispatchStreamEvent(
425→  event: string,
426→  ctx: StreamContext,
427→  state: ToolInputState,
428→): IGraphEvent | undefined {
