 44→function extractTokenUsageFromContainer(candidate: Record<string, unknown> | undefined): TokenUsageData | undefined {
 45→  if (!candidate) {
 46→    return undefined;
 47→  }
 48→
 49→  const usageMetadata = asRecord(candidate.usage_metadata) ?? asRecord(candidate.usageMetadata);
 50→  if (!usageMetadata) {
 51→    return undefined;
