import { AIMessageChunk } from '@langchain/core/messages';
import { ToolCallChunk } from '@langchain/core/messages/tool';

interface ITextContentBlock {
  type: 'text';
  text: string;
  [key: string]: unknown;
}

interface IThinkingContentBlock {
  type: 'thinking';
  thinking: string;
  [key: string]: unknown;
}

interface IToolUseContentBlock {
  type: 'tool_use';
  name: string;
  [key: string]: unknown;
}

export interface TokenUsageData {
  inputTokens: number;
  outputTokens: number;
  totalTokens: number;
  promptTokens?: number;
  completionTokens?: number;
  cachedInputTokens?: number;
  reasoningOutputTokens?: number;
}

export function getToolArgs(chunks: ToolCallChunk[] | undefined): string {
  return chunks?.map(it => it.args).filter(Boolean).join('') || '';
}

function asRecord(value: unknown): Record<string, unknown> | undefined {
  return value && typeof value === 'object' ? (value as Record<string, unknown>) : undefined;
}

function asNumber(value: unknown): number | undefined {
  return typeof value === 'number' && Number.isFinite(value) ? value : undefined;
}

function extractTokenUsageFromContainer(candidate: Record<string, unknown> | undefined): TokenUsageData | undefined {
  if (!candidate) {
    return undefined;
  }

  const usageMetadata = asRecord(candidate.usage_metadata) ?? asRecord(candidate.usageMetadata);
  if (!usageMetadata) {
    return undefined;
  }

  const inputTokens =
    asNumber(usageMetadata.input_tokens) ??
    asNumber(usageMetadata.inputTokens);
  const outputTokens =
    asNumber(usageMetadata.output_tokens) ??
    asNumber(usageMetadata.outputTokens);
  const totalTokens =
    asNumber(usageMetadata.total_tokens) ??
    asNumber(usageMetadata.totalTokens) ??
    (typeof inputTokens === 'number' && typeof outputTokens === 'number' ? inputTokens + outputTokens : undefined);

  if (typeof inputTokens !== 'number' || typeof outputTokens !== 'number' || typeof totalTokens !== 'number') {
    return undefined;
  }

  const inputTokenDetails = asRecord(usageMetadata.input_token_details) ?? asRecord(usageMetadata.inputTokenDetails);
  const outputTokenDetails = asRecord(usageMetadata.output_token_details) ?? asRecord(usageMetadata.outputTokenDetails);
  const promptTokenDetails =
    asRecord(usageMetadata.prompt_tokens_details) ??
    asRecord(usageMetadata.promptTokensDetails);
  const completionTokenDetails =
    asRecord(usageMetadata.completion_tokens_details) ??
    asRecord(usageMetadata.completionTokensDetails);

  const promptTokens = asNumber(usageMetadata.prompt_tokens) ?? asNumber(usageMetadata.promptTokens);
  const completionTokens =
    asNumber(usageMetadata.completion_tokens) ??
    asNumber(usageMetadata.completionTokens);
  const cachedInputTokens =
    asNumber(inputTokenDetails?.cache_read) ??
    asNumber(inputTokenDetails?.cacheRead) ??
    asNumber(promptTokenDetails?.cached_tokens) ??
    asNumber(promptTokenDetails?.cachedTokens);
  const reasoningOutputTokens =
    asNumber(outputTokenDetails?.reasoning) ??
    asNumber(completionTokenDetails?.reasoning_tokens) ??
    asNumber(completionTokenDetails?.reasoningTokens);

  return {
    inputTokens,
    outputTokens,
    totalTokens,
    ...(typeof promptTokens === 'number' ? { promptTokens } : {}),
    ...(typeof completionTokens === 'number' ? { completionTokens } : {}),
    ...(typeof cachedInputTokens === 'number' ? { cachedInputTokens } : {}),
    ...(typeof reasoningOutputTokens === 'number' ? { reasoningOutputTokens } : {}),
  };
}

export function extractTokenUsage(data: Record<string, unknown> | undefined): TokenUsageData | undefined {
  const output = asRecord(data?.output);
  const response = asRecord(data?.response);
  const responseOutput = asRecord(response?.output);

  const candidates: Array<Record<string, unknown> | undefined> = [
    asRecord(output?.kwargs),
    output,
    asRecord(responseOutput?.kwargs),
    responseOutput,
    data,
    response,
  ];

  for (const candidate of candidates) {
    const parsed = extractTokenUsageFromContainer(candidate);
    if (parsed) {
      return parsed;
    }
  }
  return undefined;
}

export function parseChunk({ content, tool_calls, additional_kwargs }: AIMessageChunk) {
  let text: string | undefined;
  let thinking: string | undefined;
  let tool: string | undefined;

  if (Array.isArray(content)) {
    const textBlock = content.find((it): it is ITextContentBlock => it.type === 'text');
    if (textBlock) text = textBlock.text;

    const thinkingBlock = content.find((it): it is IThinkingContentBlock => it.type === 'thinking');
    if (thinkingBlock) thinking = thinkingBlock.thinking;

    const toolUseBlock = content.find((it): it is IToolUseContentBlock => it.type === 'tool_use');
    if (toolUseBlock) tool = toolUseBlock.name;
  } else if (typeof content === 'string') {
    text = content;
    thinking = additional_kwargs.reasoning_content as string | undefined;
    tool = tool_calls?.at(0)?.name;
  }

  return { text, thinking, tool };
}

export function resolveToolOutput(artifact: unknown, content: unknown): unknown {
  if (artifact instanceof Error) return undefined;
  const hasArtifact = Array.isArray(artifact) ? artifact.length > 0 : !!artifact;
  return hasArtifact ? artifact : content;
}

export function extractToolError(value: unknown): string | undefined {
  if (value instanceof Error) {
    return value.message;
  }

  if (!value || typeof value !== 'object') {
    return undefined;
  }

  const record = value as Record<string, unknown>;
  if (typeof record.error === 'string') {
    return record.error;
  }

  if (record.status === 'error') {
    if (typeof record.content === 'string') {
      return record.content;
    }

    return tryJSONStringify(record.content) ?? tryJSONStringify(record.artifact);
  }

  return undefined;
}

export function tryJSONStringify(value: unknown): string | undefined {
  try {
    return JSON.stringify(value);
  } catch {
    return undefined;
  }
}

