  for (let index = messages.length - 1; index >= 0; index -= 1) {
    const message = messages[index];
    if (Array.isArray(message?.todos)) {
      return message.todos;
    }
  }

  return [];
}

function isSubagentCompleted(messages: Message[]): boolean {
  const lastMessage = messages.at(-1);
  if (lastMessage?.event === EVENT_TOOL_CALL_RESULT && lastMessage?.toolName === 'task') {
    return true;
  }
  return false;
}

function hasSubagentError(messages: Message[]): boolean {
  return messages.some(
    message => message.event === EVENT_TOOL_CALL_RESULT && message.toolName === 'task' && !!message.error,
  );
}

export function buildSubagentDisplayState({
  key,
  label,
  messages,
}: BuildSubagentDisplayStateOptions): SubagentDisplayState {
  const taskDescription = getTaskDescription(messages);
  const latestAssistantContent = getLatestAssistantContent(messages);
  const todos = getLatestSubagentTodos(messages);
  const completed = isSubagentCompleted(messages);
  const preview = completed ? 'completed' : latestAssistantContent || taskDescription || '处理中...';

  return {
    key,
    label,
    taskDescription,
    latestAssistantContent,
    preview,
    completed,
    todos,
    showTodoPanel: !completed && todos.length > 0,
  };
}

